@_documentation(visibility: private)
#endif
public func FfiConverterTypeOrchestratorCore_lift(_ pointer: UnsafeMutableRawPointer) throws -> OrchestratorCore {
    return try FfiConverterTypeOrchestratorCore.lift(pointer)
}

