/**
 * Information about a detected provider.
 */
public struct ProviderInfo {
    public var id: String
    public var displayName: String
    public var available: Bool
    public var connected: Bool
    public var subtitle: String

    // Default memberwise initializers are never public by default, so we
    // declare one manually.
    public init(id: String, displayName: String, available: Bool, connected: Bool, subtitle: String) {
        self.id = id
        self.displayName = displayName
        self.available = available
        self.connected = connected
        self.subtitle = subtitle
    }
}

#if compiler(>=6)
extension ProviderInfo: Sendable {}
#endif


extension ProviderInfo: Equatable, Hashable {
    public static func ==(lhs: ProviderInfo, rhs: ProviderInfo) -> Bool {
        if lhs.id != rhs.id {
            return false
        }
        if lhs.displayName != rhs.displayName {
            return false
        }
        if lhs.available != rhs.available {
            return false
        }
        if lhs.connected != rhs.connected {
            return false
        }
        if lhs.subtitle != rhs.subtitle {
            return false
        }
        return true
    }

    public func hash(into hasher: inout Hasher) {
        hasher.combine(id)
        hasher.combine(displayName)
        hasher.combine(available)
        hasher.combine(connected)
        hasher.combine(subtitle)
    }
}



