    typealias SwiftType = FfiOnboardingStep

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiOnboardingStep {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .identity
        
        case 2: return .openClawImport
        
        case 3: return .relay
        
        case 4: return .providers
        
        case 5: return .llMs
        
        case 6: return .mobileSetup
        
        default: throw UniffiInternalError.unexpectedEnumCase
        }
    }

    public static func write(_ value: FfiOnboardingStep, into buf: inout [UInt8]) {
        switch value {
        
        
        case .identity:
            writeInt(&buf, Int32(1))
        
        
        case .openClawImport:
            writeInt(&buf, Int32(2))
        
        
        case .relay:
            writeInt(&buf, Int32(3))
        
        
        case .providers:
            writeInt(&buf, Int32(4))
        
        
        case .llMs:
            writeInt(&buf, Int32(5))
        
        
        case .mobileSetup:
            writeInt(&buf, Int32(6))
        
        }
    }
}


