#endif

#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeFfiProcessStatus: FfiConverterRustBuffer {
    typealias SwiftType = FfiProcessStatus

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> FfiProcessStatus {
        let variant: Int32 = try readInt(&buf)
        switch variant {
        
        case 1: return .stopped
        
